import React from "react";

const education = [
  {
    university: "Medi-Caps University",
    course: "B.Tech CS",
    cgpa: "9.34/10",
    percentage: null,
    year: "2019-2023",
    place: "Indore, India",
  },
  {
    university: "First Step Sr Secondary School",
    course: "HSC, Science",
    cgpa: null,
    percentage: "85%",
    year: "2018-2019",
    place: "Chhindwara, India",
  },
];

const Card = ({ data }) => {
  const { university, course, cgpa, percentage, year, place } = data;
  return (
    <section
      data-aos="fade-up"
      className="bg-gray-100 shadow-md border-indigo-900 border-l-4 h-max mx-auto my-2 px-2 sm:m-4  py-1 rounded sm:w-96 w-80"
    >
      <div className="flex items-center justify-between">
        <h1 className="text-indigo-900">{course}</h1>
        <h1>{year}</h1>
      </div>
      <h1 className="h-px my-1 bg-gray-900"></h1>

      <h1 className="font-semibold">{university}</h1>
      <h1>{place}</h1>
      <h1>
        {(percentage && `Percentage: ${percentage}`) ||
          (cgpa && `CGPA: ${cgpa}`)}
      </h1>
    </section>
  );
};

const Education = () => {
  return (
    <>
      <section id="education" className="mt-16 font-mono">
        {/* Education */}
        <section>
          <div className="flex justify-between items-center mt-4">
            <div className=" w-4 h-px bg-gray-900 "></div>
            <h1 className="font-serif text-5xl p-2 border-2 border-gray-900 ">
              Education
            </h1>
            <div className=" flex-1 h-px bg-gray-900 "></div>
          </div>
          <div className="sm:ml-4 flex flex-col justify-start flex-wrap items-start">
            {education.map((data, index) => {
              return <Card data={data} id={index} />;
            })}
          </div>
        </section>
      </section>
    </>
  );
};

export default Education;
