import React from "react";

const experience = [
  {
    role: "Software Developer Intern",
    oranisation: "MADIEE Games",
    duration: "July'21 - Sept'21",
    experience: "Worked on React JS.Developed UI for web games",
  },
];

const por = [
  {
    role: "Web Developer, Graphic Designer",
    oranisation: "Incubation Cell, Medi-Caps University",
    duration: "Oct'20 - present",
    experience:
      "Worked in Web Development and Graphic Designing team.Working on MIIC website.Led a team to produce UX/UI designs and posters for website and events",
  },
  {
    role: "Chapter Lead",
    oranisation: "CodeChef College Chapter",
    duration: "May'20 - June'21",
    experience:
      "Established first-ever active competitive programming club on my campus.Guided 250+ students to get started with Competitve Programming, took doubt session organised coding contests and workshops ",
  },
];

const Card = ({ data }) => {
  const { role, oranisation, duration, experience } = data;
  return (
    <section
      data-aos="fade-up"
      className="bg-gray-100 shadow-md border-indigo-900 border-l-4 h-max mx-auto my-2 px-2 sm:m-4  py-1 rounded sm:w-96 w-80"
    >
      <h1 className="text-md text-indigo-900">{role}</h1>
      <h1 className="text-lg font-bold">{oranisation}</h1>
      <h1 className="h-px my-1 bg-gray-900"></h1>
      <h1 className="text-sm text-gray-700">{duration}</h1>
      {experience.split(".").map((item, index) => {
        return (
          <h1 key={index}>
            <span className="text-lg text-indigo-900 font-bold">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                className="inline h-6 w-6"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  stroke-linecap="round"
                  stroke-linejoin="round"
                  stroke-width="2"
                  d="M5 13l4 4L19 7"
                />
              </svg>
              {item[0]}
            </span>
            {item.slice(1)}
          </h1>
        );
      })}
    </section>
  );
};

const Experience = () => {
  return (
    <section id="experience" className="mt-16 font-mono">
      {/* Experience */}
      <section>
        <div className="flex justify-between items-center mt-4">
          <div className=" w-4 h-px bg-gray-900 "></div>
          <h1 className="font-serif text-5xl p-2 border-2 border-gray-900 ">
            Experience
          </h1>
          <div className=" flex-1 h-px bg-gray-900 "></div>
        </div>
        <div className="sm:ml-4 flex justify-start flex-wrap items-start">
          {experience.map((data, index) => {
            return <Card data={data} id={index} />;
          })}
        </div>
      </section>
    </section>
  );
};

export default Experience;
